def t(key: str, lang: str = DEFAULT_LANG, **kwargs) -> str:
    """
    Retourne la chaîne traduite pour `key` dans la langue `lang`.
    Si la clé ou la langue est absente, retombe sur le français,
    puis sur la clé elle-même en dernier recours.
    Supporte le formatage avec **kwargs (ex: t("log_page", lang, n=3)).
    """
    entry = TRANSLATIONS.get(key)
    if entry is None:
        return key
    text = entry.get(lang) or entry.get(DEFAULT_LANG) or key
    if kwargs:
        try:
            return text.format(**kwargs)
        except Exception:
            return text
    return text
